// Filtra le fatture non pagate in scadenza entro 3 giorni o già scadute
const oggi = new Date();
oggi.setHours(0, 0, 0, 0);

const daAvvisare = [];

for (const item of $input.all()) {
  const f = item.json;
  const stato = String(f.Stato || '').trim().toLowerCase();
  if (stato === 'pagata') continue;

  // Data in formato gg/mm/aaaa
  const parti = String(f.Scadenza || '').split('/');
  if (parti.length !== 3) continue;
  const scadenza = new Date(Number(parti[2]), Number(parti[1]) - 1, Number(parti[0]));

  const giorniMancanti = Math.round((scadenza - oggi) / 86400000);

  if (giorniMancanti <= 3) {
    daAvvisare.push({
      json: {
        ...f,
        giorniMancanti,
        scaduta: giorniMancanti < 0,
        scadenzaTesto: `${parti[0]}/${parti[1]}/${parti[2]}`
      }
    });
  }
}

return daAvvisare;
